// github_client_retries.go
package github

import (
	"context"
	"fmt"
	"log"
	"time"

	"github.com/google/go-github/v62/github" // Adjust version as per Atlantis's dependency
	"golang.org/x/oauth2"
)

// GitHubClientWithRetries wraps the standard GitHub client with retry logic
// to handle transient API errors, such as GitHub's backend server health issues
// or temporary rate limits.
type GitHubClientWithRetries struct {
	client         *github.Client
	maxRetries     int
	initialBackoff time.Duration
}

// NewGitHubClientWithRetries creates a new GitHub client instance
// configured with retry capabilities.
//
// ctx: The context for the underlying HTTP client.
// token: The GitHub personal access token or OAuth token.
// maxRetries: The maximum number of retry attempts for a failed API call.
// initialBackoff: The starting duration for exponential backoff between retries.
func NewGitHubClientWithRetries(ctx context.Context, token string, maxRetries int, initialBackoff time.Duration) *GitHubClientWithRetries {
	ts := oauth2.StaticTokenSource(
		&oauth2.Token{AccessToken: token},
	)
	tc := oauth2.NewClient(ctx, ts)
	return &GitHubClientWithRetries{
		client:         github.NewClient(tc),
		maxRetries:     maxRetries,
		initialBackoff: initialBackoff,
	}
}

// CallWithRetries executes a GitHub API call with exponential backoff retry logic.
// It attempts to re-execute the `apiCall` function if it encounters transient errors
// (e.g., 5xx HTTP status codes, rate limits, or network issues) up to `maxRetries` times.
//
// apiCall: A function encapsulating the actual GitHub API interaction. It should
//          return the GitHub response and any error encountered.
func (c *GitHubClientWithRetries) CallWithRetries(ctx context.Context, apiCall func(ctx context.Context) (*github.Response, error)) (*github.Response, error) {
	var resp *github.Response
	var err error
	backoff := c.initialBackoff

	for i := 0; i < c.maxRetries; i++ {
		resp, err = apiCall(ctx)
		if err == nil {
			return resp, nil // API call successful
		}

		// Determine if the error is transient and warrants a retry.
		// This includes server-side errors (5xx), rate limits (403 with specific headers/messages),
		// or general network errors.
		isTransient := false
		if ghErr, ok := err.(*github.ErrorResponse); ok {
			// Common transient HTTP status codes:
			// 5xx: Server errors (e.g., 500, 502, 503, 504)
			// 403: Can indicate rate limiting if accompanied by X-RateLimit-Remaining: 0
			//      or specific error messages. For simplicity, we'll treat 403 as potentially transient.
			if ghErr.Response != nil && (ghErr.Response.StatusCode >= 500 || ghErr.Response.StatusCode == 403) {
				isTransient = true
			}
		} else if err != nil {
			// Catch-all for other errors that might be transient (e.g., network issues,
			// context deadlines if not explicitly handled by the caller).
			// A more robust implementation might inspect the error type more closely.
			isTransient = true
		}

		if !isTransient {
			return resp, err // Not a transient error, return immediately
		}

		log.Printf("GitHub API call failed (attempt %d/%d): %v. Retrying in %v...", i+1, c.maxRetries, err, backoff)

		select {
		case <-time.After(backoff):
			backoff *= 2 // Exponential backoff
		case <-ctx.Done():
			return nil, ctx.Err() // Context cancelled, stop retrying
		}
	}

	// All retries exhausted, return the last error.
	return resp, fmt.Errorf("GitHub API call failed after %d retries: %w", c.maxRetries, err)
}

// GetClient returns the underlying *github.Client for direct API calls
// if specific methods are not wrapped by CallWithRetries.
func (c *GitHubClientWithRetries) GetClient() *github.Client {
	return c.client
}
